--
-- Table structure for table `TaskPhoto`
--

DROP TABLE IF EXISTS `TaskPhoto`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `TaskPhoto` (
  `id` int NOT NULL AUTO_INCREMENT,
  `url` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `createdAt` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  `updatedAt` datetime(3) NOT NULL,
  `staffId` int DEFAULT NULL,
  `supplierId` int DEFAULT NULL,
  `taskId` int NOT NULL,
  PRIMARY KEY (`id`),
  KEY `TaskPhoto_staffId_fkey` (`staffId`),
  KEY `TaskPhoto_supplierId_fkey` (`supplierId`),
  KEY `TaskPhoto_taskId_fkey` (`taskId`),
  CONSTRAINT `TaskPhoto_staffId_fkey` FOREIGN KEY (`staffId`) REFERENCES `Staff_Member` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `TaskPhoto_supplierId_fkey` FOREIGN KEY (`supplierId`) REFERENCES `Supplier` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `TaskPhoto_taskId_fkey` FOREIGN KEY (`taskId`) REFERENCES `Task` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=53 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

